def next_value(x, seen):
    # Rule 2: odd -> 2x + 2
    if x % 2 == 1:
        return 2 * x + 2
    # Rule 3: even -> x/2
    half = x // 2
    # Rule 4: but if x/2 already appeared -> x + 1 instead
    if half in seen:
        return x + 1
    return half
def generate_sequence(limit):
    seq = [1]
    seen = {1}
    while len(seq) < limit:
        x = seq[-1]
        nxt = next_value(x, seen)
        seq.append(nxt)
        seen.add(nxt)
    return seq
print(generate_sequence(70))

